using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    /// <summary>
    /// Helper to create an in-memory SchoolContext for testing.
    /// </summary>
    internal static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateWithSeedData(string dbName = null)
        {
            var context = Create(dbName);
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            context.Departments.Add(dept);

            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = DateTime.Parse("2000-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Instructors.Add(instructor);

            dept.InstructorID = instructor.ID;

            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = dept.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Courses.Add(course);

            var student = new Student
            {
                ID = 1,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.Parse("2020-09-01"),
                Enrollments = new List<Enrollment>()
            };
            context.Students.Add(student);

            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = course.CourseID,
                StudentID = student.ID,
                Grade = Grade.A
            };
            context.Enrollments.Add(enrollment);

            context.SaveChanges();
        }
    }
}

