namespace ContosoUniversity.Tests.Data
{
    [TestClass]
    public sealed class SchoolContextTests
    {
        [TestMethod]
        public void SchoolContext_CanBeCreatedWithInMemory()
        {
            using var context = TestDbContextFactory.Create();
            Assert.IsNotNull(context);
            Assert.IsNotNull(context.Students);
            Assert.IsNotNull(context.Courses);
            Assert.IsNotNull(context.Departments);
            Assert.IsNotNull(context.Instructors);
            Assert.IsNotNull(context.Enrollments);
            Assert.IsNotNull(context.CourseAssignments);
            Assert.IsNotNull(context.OfficeAssignments);
            Assert.IsNotNull(context.People);
            Assert.IsNotNull(context.Notifications);
        }

        [TestMethod]
        public void SchoolContext_CanAddAndRetrieveStudent()
        {
            using var context = TestDbContextFactory.Create();
            var student = new Student
            {
                LastName = "TestLast",
                FirstMidName = "TestFirst",
                EnrollmentDate = System.DateTime.Parse("2020-01-01")
            };

            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.First();
            Assert.AreEqual("TestLast", retrieved.LastName);
            Assert.AreEqual("TestFirst", retrieved.FirstMidName);
        }

        [TestMethod]
        public void SchoolContext_CanAddAndRetrieveCourse()
        {
            using var context = TestDbContextFactory.Create();
            var dept = new Department
            {
                Name = "Test",
                Budget = 100000,
                StartDate = System.DateTime.Parse("2020-01-01")
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 9999,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var retrieved = context.Courses.First(c => c.CourseID == 9999);
            Assert.AreEqual("Test Course", retrieved.Title);
            Assert.AreEqual(3, retrieved.Credits);
        }

        [TestMethod]
        public void SchoolContext_CourseAssignment_CompositeKey()
        {
            using var context = TestDbContextFactory.Create();

            var instructor = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                HireDate = System.DateTime.Parse("2020-01-01"),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };
            context.Instructors.Add(instructor);

            var dept = new Department
            {
                Name = "Math",
                Budget = 50000,
                StartDate = System.DateTime.Parse("2020-01-01")
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 8888,
                Title = "Algebra",
                Credits = 3,
                DepartmentID = dept.DepartmentID,
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var ca = new CourseAssignment
            {
                CourseID = course.CourseID,
                InstructorID = instructor.ID
            };
            context.CourseAssignments.Add(ca);
            context.SaveChanges();

            var retrieved = context.CourseAssignments.First();
            Assert.AreEqual(course.CourseID, retrieved.CourseID);
            Assert.AreEqual(instructor.ID, retrieved.InstructorID);
        }

        [TestMethod]
        public void SchoolContext_CanAddDepartmentWithInstructor()
        {
            using var context = TestDbContextFactory.Create();

            var instructor = new Instructor
            {
                LastName = "Admin",
                FirstMidName = "Prof",
                HireDate = System.DateTime.Parse("1999-01-01"),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var dept = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = System.DateTime.Parse("2010-01-01"),
                InstructorID = instructor.ID
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var retrieved = context.Departments.Include(d => d.Administrator).First();
            Assert.AreEqual("Physics", retrieved.Name);
            Assert.AreEqual(200000, retrieved.Budget);
            Assert.IsNotNull(retrieved.Administrator);
            Assert.AreEqual("Admin", retrieved.Administrator.LastName);
        }

        [TestMethod]
        public void SchoolContext_CanAddEnrollment()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            var enrollments = context.Enrollments.ToList();
            Assert.IsTrue(enrollments.Count > 0);
            Assert.AreEqual(Grade.A, enrollments.First().Grade);
        }

        [TestMethod]
        public void SchoolContext_CanAddOfficeAssignment()
        {
            using var context = TestDbContextFactory.Create();

            var instructor = new Instructor
            {
                LastName = "Test",
                FirstMidName = "Inst",
                HireDate = System.DateTime.Parse("2020-01-01"),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var oa = new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Room 101"
            };
            context.OfficeAssignments.Add(oa);
            context.SaveChanges();

            var retrieved = context.OfficeAssignments.First();
            Assert.AreEqual("Room 101", retrieved.Location);
            Assert.AreEqual(instructor.ID, retrieved.InstructorID);
        }

        [TestMethod]
        public void SchoolContext_CanAddNotification()
        {
            using var context = TestDbContextFactory.Create();
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = System.DateTime.Now,
                CreatedBy = "Test",
                IsRead = false
            };
            context.Notifications.Add(notification);
            context.SaveChanges();

            var retrieved = context.Notifications.First();
            Assert.AreEqual("Student", retrieved.EntityType);
            Assert.AreEqual("CREATE", retrieved.Operation);
        }
    }
}

