using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using System.Linq;

namespace ContosoUniversity.Tests.Data
{
    [TestClass]
    public sealed class DbInitializerTests
    {
        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsData()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();

            // Act
            DbInitializer.Initialize(context);

            // Assert - verify students were seeded
            Assert.AreEqual(8, context.Students.Count());
            Assert.IsTrue(context.Students.Any(s => s.LastName == "Alexander"));
            Assert.IsTrue(context.Students.Any(s => s.LastName == "Alonso"));

            // Verify instructors
            Assert.AreEqual(5, context.Instructors.Count());
            Assert.IsTrue(context.Instructors.Any(i => i.LastName == "Abercrombie"));

            // Verify departments
            Assert.AreEqual(4, context.Departments.Count());
            Assert.IsTrue(context.Departments.Any(d => d.Name == "English"));
            Assert.IsTrue(context.Departments.Any(d => d.Name == "Mathematics"));

            // Verify courses
            Assert.AreEqual(7, context.Courses.Count());
            Assert.IsTrue(context.Courses.Any(c => c.Title == "Chemistry"));
            Assert.IsTrue(context.Courses.Any(c => c.Title == "Calculus"));

            // Verify enrollments
            Assert.IsTrue(context.Enrollments.Count() > 0);

            // Verify office assignments
            Assert.AreEqual(3, context.OfficeAssignments.Count());

            // Verify course assignments
            Assert.AreEqual(8, context.CourseAssignments.Count());
        }

        [TestMethod]
        public void Initialize_AlreadySeeded_DoesNotDuplicate()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();

            // Act - initialize twice
            DbInitializer.Initialize(context);
            var firstStudentCount = context.Students.Count();

            DbInitializer.Initialize(context);
            var secondStudentCount = context.Students.Count();

            // Assert - count should be the same
            Assert.AreEqual(firstStudentCount, secondStudentCount);
            Assert.AreEqual(8, secondStudentCount);
        }

        [TestMethod]
        public void Initialize_SeedsCorrectStudentNames()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            var carson = context.Students.First(s => s.LastName == "Alexander");
            Assert.AreEqual("Carson", carson.FirstMidName);

            var meredith = context.Students.First(s => s.LastName == "Alonso");
            Assert.AreEqual("Meredith", meredith.FirstMidName);
        }

        [TestMethod]
        public void Initialize_SeedsCorrectEnrollmentGrades()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            var alexanderChemistry = context.Enrollments
                .First(e => e.Student.LastName == "Alexander" && e.Course.Title == "Chemistry");
            Assert.AreEqual(Grade.A, alexanderChemistry.Grade);
        }

        [TestMethod]
        public void Initialize_SeedsDepartmentsWithInstructors()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            var english = context.Departments.First(d => d.Name == "English");
            Assert.IsNotNull(english.InstructorID);

            var instructor = context.Instructors.Find(english.InstructorID);
            Assert.AreEqual("Abercrombie", instructor.LastName);
        }

        [TestMethod]
        public void Initialize_SeedsOfficeAssignments()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            var fakhouri = context.Instructors.First(i => i.LastName == "Fakhouri");
            var office = context.OfficeAssignments.Find(fakhouri.ID);
            Assert.IsNotNull(office);
            Assert.AreEqual("Smith 17", office.Location);
        }
    }
}

