using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            SeedStudents(_context);
            _controller = new StudentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        private static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = DateTime.Parse("2020-09-01"), Enrollments = new List<Enrollment>() },
                new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = DateTime.Parse("2021-09-01"), Enrollments = new List<Enrollment>() },
                new Student { LastName = "Baker", FirstMidName = "Tom", EnrollmentDate = DateTime.Parse("2019-09-01"), Enrollments = new List<Enrollment>() }
            );
            context.SaveChanges();
        }

        [TestMethod]
        public void Index_NoParams_ReturnsViewWithStudents()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
        }

        [TestMethod]
        public void Index_DefaultSort_OrdersByLastNameAsc()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual("Alexander", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Baker", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_OrdersByLastNameDesc()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual("Baker", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Alexander", model[2].LastName);
        }

        [TestMethod]
        public void Index_DateSort_OrdersByEnrollmentDateAsc()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual("Baker", model[0].LastName); // 2019
            Assert.AreEqual("Alexander", model[1].LastName); // 2020
            Assert.AreEqual("Alonso", model[2].LastName); // 2021
        }

        [TestMethod]
        public void Index_DateDescSort_OrdersByEnrollmentDateDesc()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual("Alonso", model[0].LastName); // 2021
        }

        [TestMethod]
        public void Index_SearchString_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Alex", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchByFirstName_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Carson", model[0].FirstMidName);
        }

        [TestMethod]
        public void Index_SearchString_ResetsPage()
        {
            var result = _controller.Index(null, null, "Alex", null) as ViewResult;
            // When searchString is not null, page should be reset to 1
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Index_CurrentFilter_UsedWhenSearchStringNull()
        {
            var result = _controller.Index(null, "Alex", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var student = _context.Students.First();
            // Need to add enrollment data for includes
            var dept = new Department { Name = "Test", Budget = 1000, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 5000, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID, Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment { StudentID = student.ID, CourseID = course.CourseID, Grade = Grade.A };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var result = _controller.Details(student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(student.LastName, model.LastName);
        }

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Create_Get_ReturnsViewWithStudent()
        {
            var result = _controller.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        [TestMethod]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(4, _context.Students.Count());
        }

        [TestMethod]
        public void Create_Post_MinValueDate_ReturnsView()
        {
            var student = new Student
            {
                LastName = "Bad",
                FirstMidName = "Date",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Create_Post_DateOutOfRange_ReturnsView()
        {
            var student = new Student
            {
                LastName = "Bad",
                FirstMidName = "Date",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student { EnrollmentDate = DateTime.Parse("2023-01-01") };

            var result = _controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var student = _context.Students.First();
            var result = _controller.Edit(student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(student.LastName, model.LastName);
        }

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = _context.Students.First();
            // Detach tracking entity
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editedStudent = new Student
            {
                ID = student.ID,
                LastName = "Updated",
                FirstMidName = student.FirstMidName,
                EnrollmentDate = student.EnrollmentDate
            };

            var result = _controller.Edit(editedStudent) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_MinValueDate_ReturnsView()
        {
            var student = _context.Students.First();
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editedStudent = new Student
            {
                ID = student.ID,
                LastName = student.LastName,
                FirstMidName = student.FirstMidName,
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(editedStudent) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            var student = _context.Students.First();
            var result = _controller.Delete(student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(student.LastName, model.LastName);
        }

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesAndRedirects()
        {
            var student = _context.Students.First();
            var result = _controller.DeleteConfirmed(student.ID) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(2, _context.Students.Count());
        }

        [TestMethod]
        public void Index_SetsViewBagSortParameters()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
            Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
        }

        [TestMethod]
        public void Index_WithNameDescSort_SetsAlternateSort()
        {
            _controller.Index("name_desc", null, null, null);
            Assert.AreEqual("", _controller.ViewBag.NameSortParm);
        }

        [TestMethod]
        public void Index_WithDateSort_SetsAlternateDateSort()
        {
            _controller.Index("Date", null, null, null);
            Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
        }
    }
}

