            Assert.IsNotNull(result);
            var model = result.Model as Department;
            Assert.IsNotNull(model);
            Assert.AreEqual(dept.Name, model.Name);
        }

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var dept = _context.Departments.First();
            _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editedDept = new Department
            {
                DepartmentID = dept.DepartmentID,
                Name = "Updated English",
                Budget = 400000,
                StartDate = dept.StartDate,
                InstructorID = dept.InstructorID
            };

            var result = _controller.Edit(editedDept) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department { DepartmentID = 1 };

            var result = _controller.Edit(dept) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithDepartment()
        {
            var dept = _context.Departments.First();
            var result = _controller.Delete(dept.DepartmentID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Department;
            Assert.IsNotNull(model);
        }

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesAndRedirects()
        {
            var dept = _context.Departments.First();
            var result = _controller.DeleteConfirmed(dept.DepartmentID) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(1, _context.Departments.Count());
        }

        [TestMethod]
        public void Index_IncludesAdministrator()
        {
            var result = _controller.Index() as ViewResult;
            var model = result.Model as List<Department>;

            var english = model.First(d => d.Name == "English");
            Assert.IsNotNull(english.Administrator);
            Assert.AreEqual("Smith", english.Administrator.LastName);
        }
    }
}

