namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        private SchoolContext _context;
        private HomeController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            _controller = new HomeController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void About_ReturnsViewWithEnrollmentData()
        {
            // Seed some students
            _context.Students.AddRange(
                new Student { LastName = "A", FirstMidName = "B", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { LastName = "C", FirstMidName = "D", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { LastName = "E", FirstMidName = "F", EnrollmentDate = DateTime.Parse("2021-09-01") }
            );
            _context.SaveChanges();

            var result = _controller.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count); // 2 distinct dates

            var group2020 = model.First(g => g.EnrollmentDate.Value.Year == 2020);
            Assert.AreEqual(2, group2020.StudentCount);

            var group2021 = model.First(g => g.EnrollmentDate.Value.Year == 2021);
            Assert.AreEqual(1, group2021.StudentCount);
        }

        [TestMethod]
        public void About_EmptyDb_ReturnsEmptyList()
        {
            var result = _controller.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void Contact_ReturnsViewWithMessage()
        {
            var result = _controller.Contact() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsView()
        {
            var result = _controller.Error() as ViewResult;
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            var result = _controller.Unauthorized() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

