    [TestClass]
    public sealed class InstructorsControllerTests
    {
        private SchoolContext _context;
        private InstructorsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            SeedInstructors(_context);
            _controller = new InstructorsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        private static void SeedInstructors(SchoolContext context)
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var instructor1 = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = DateTime.Parse("2000-01-01"),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
            };
            var instructor2 = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                HireDate = DateTime.Parse("2005-06-15"),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Instructors.AddRange(instructor1, instructor2);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = dept.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var ca = new CourseAssignment
            {
                CourseID = course.CourseID,
                InstructorID = instructor1.ID
            };
            context.CourseAssignments.Add(ca);
            context.SaveChanges();
        }

        [TestMethod]
        public void Index_NoParams_ReturnsViewWithInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Instructors.Count());
        }

        [TestMethod]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var instructor = _context.Instructors.First(i => i.LastName == "Smith");
            var result = _controller.Index(instructor.ID, null) as ViewResult;

            var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model.Courses);
            Assert.AreEqual(1, model.Courses.Count());
            Assert.AreEqual("Chemistry", model.Courses.First().Title);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.Details(instructor.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.AreEqual(instructor.LastName, model.LastName);
        }

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(9999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.CourseAssignments);
        }

        [TestMethod]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "New",
                FirstMidName = "Instructor",
                HireDate = DateTime.Parse("2023-01-01")
            };

            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(3, _context.Instructors.Count());
        }

        [TestMethod]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "New",
                FirstMidName = "Instructor",
                HireDate = DateTime.Parse("2023-01-01")
            };
            var selectedCourses = new[] { "1050" };

            var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            var created = _context.Instructors.First(i => i.LastName == "New");
            Assert.AreEqual(1, _context.CourseAssignments.Count(ca => ca.InstructorID == created.ID));
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor { HireDate = DateTime.Parse("2023-01-01"), CourseAssignments = new List<CourseAssignment>() };

            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
