using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            _controller = new NotificationsController(_context);

            // Drain the static queue to ensure clean state
            var tempService = new NotificationService();
            while (tempService.ReceiveNotification() != null) { }
            tempService.Dispose();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.IsNotNull(result);
            // The result is JsonResult, verify it has a value
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Enqueue a notification
            var service = new NotificationService();
            service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");

            var result = _controller.GetNotifications();

            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void MarkAsRead_ValidId_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;
            Assert.IsNotNull(result);
        }
    }
}

