    [TestClass]
    public sealed class SchoolContextFactoryTests
    {
        [TestMethod]
        public void Create_WithValidConfig_ReturnsSchoolContext()
        {
            // Arrange
            var config = new ConfigurationBuilder()
                .AddInMemoryCollection(new Dictionary<string, string>
                {
                    ["ConnectionStrings:DefaultConnection"] = "Server=(localdb)\\mssqllocaldb;Database=TestDb;Trusted_Connection=True;"
                })
                .Build();

            // Act
            var context = SchoolContextFactory.Create(config);

            // Assert
            Assert.IsNotNull(context);
            context.Dispose();
        }
    }
}

